create table tensorboards
(
    id            bigint unsigned auto_increment
        primary key,
    created_at    datetime(3)  null,
    updated_at    datetime(3)  null,
    deleted_at    datetime(3)  null,
    instance_name varchar(191) null comment '实例名称',
    owner_type    varchar(191) null comment '所有者类型',
    owner_id      bigint       null comment '所有者ID',
    namespace     varchar(191) null comment '命名空间',
    logs_path     varchar(191) null comment '日志路径',
    status        varchar(191) null comment '状态',
    user_id       bigint       null comment '用户ID',
    cluster_id    bigint       null comment '集群ID'
);

create index idx_tensorboards_deleted_at
    on tensorboards (deleted_at);

